files.content:
.mrg-prose {
  color: var(--mrg-semantic-color-foreground-primary);
  font-family: var(--mrg-semantic-font-family-prose);
  font-size: var(--mrg-semantic-font-size-body);
  line-height: var(--mrg-semantic-font-line-height-body);
  max-inline-size: var(--mrg-semantic-container-prose);
  min-inline-size: 0;
  overflow-wrap: anywhere;
  text-wrap: pretty;
}
.mrg-prose[data-measure="wide"] {
  max-inline-size: var(--mrg-semantic-container-content);
}
.mrg-prose[data-measure="none"] {
  max-inline-size: none;
}
.mrg-prose[data-size="compact"] {
  font-size: var(--mrg-semantic-font-size-label);
}
.mrg-prose[data-size="large"] {
  font-size: var(--mrg-semantic-font-size-body-large);
}

.mrg-prose
  :where(p, ul, ol, dl, blockquote, pre, figure):not(
    [data-prose-unstyled],
    [data-prose-unstyled] *
  ) {
  margin-block: 0 var(--mrg-semantic-space-stack-md);
}
.mrg-prose :where(h1, h2, h3, h4, h5, h6):not([data-prose-unstyled], [data-prose-unstyled] *) {
  font-family: var(--mrg-semantic-font-family-prose);
  line-height: var(--mrg-semantic-font-line-height-heading);
  margin-block: var(--mrg-semantic-space-stack-lg) var(--mrg-semantic-space-stack-sm);
  overflow-wrap: anywhere;
  text-wrap: balance;
}
.mrg-prose :where(a):not([data-prose-unstyled], [data-prose-unstyled] *) {
  color: var(--mrg-semantic-color-brand-action);
  text-decoration-thickness: var(--mrg-semantic-border-width-default);
  text-underline-offset: 0.18em;
}
.mrg-prose :where(img, video, table, pre):not([data-prose-unstyled], [data-prose-unstyled] *) {
  max-inline-size: 100%;
}
.mrg-prose :where(table):not([data-prose-unstyled], [data-prose-unstyled] *) {
  border-collapse: collapse;
  inline-size: 100%;
}
.mrg-prose :where(th, td):not([data-prose-unstyled], [data-prose-unstyled] *) {
  border-block-end: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-default);
  padding-block: var(--mrg-semantic-space-inline-sm);
  padding-inline: var(--mrg-semantic-space-inline-md);
  text-align: start;
}
@media (forced-colors: active) {
  .mrg-prose {
    color: CanvasText;
  }
  .mrg-prose :where(a):not([data-prose-unstyled], [data-prose-unstyled] *) {
    color: LinkText;
  }
}

import { createElement, forwardRef, type HTMLAttributes, type ReactNode } from "react";

import "./prose.css";

export type ProseElement = "article" | "div" | "section";
export type ProseMeasure = "prose" | "wide" | "none";
export type ProseSize = "compact" | "default" | "large";

export interface ProseProps extends HTMLAttributes<HTMLElement> {
  readonly as?: ProseElement;
  readonly children?: ReactNode;
  readonly measure?: ProseMeasure;
  readonly size?: ProseSize;
}

export const Prose = forwardRef<HTMLElement, ProseProps>(function Prose(
  { as = "article", children, className, measure = "prose", size = "default", ...nativeProps },
  forwardedRef,
) {
  return createElement(
    as,
    {
      ...nativeProps,
      className:
        className === undefined || className.trim().length === 0
          ? "mrg-prose"
          : `mrg-prose ${className}`,
      "data-measure": measure,
      "data-size": size,
      "data-slot": "prose",
      ref: forwardedRef,
    },
    children,
  );
});

Prose.displayName = "Prose";
